sql:
SELECT COUNT(gene_id) AS gene_count
FROM pathway_members
WHERE pathway_id = 1;

SELECT COUNT(*) AS citation_count
FROM pathway_citations
WHERE pathway_id = 1;

SELECT MAX(publication_date) AS most_recent_publication_date
FROM pathway_citations
WHERE pathway_id = 1;

SELECT method
FROM enrichment
WHERE p_value < 0.05;

SELECT COUNT(gene_id) AS gene_count
FROM gene_ontology
WHERE term_id = 0;

SELECT term_id
FROM enrichment_terms
WHERE enrichment_score > 2.0 AND evidence_code = 'EXP';

SELECT COUNT(citation_id) AS citation_count
FROM literature
WHERE term_id = 1;

SELECT pathway_name
FROM pathways
WHERE pathway_id IN (
  SELECT pathway_id
  FROM pathway_citations
);

SELECT ontology_name
FROM ontologies
WHERE last_updated = (SELECT MIN(last_updated) FROM ontologies);

